// ============================================
// AUTO-LINT MODULE - Automatic Lint Fixing for AI-Generated Code
// ============================================
// Automatically fixes lint errors in code generated by the agent

const autoLintState = {
  enabled: true,
  lastResults: null,
  fixHistory: [],
  supportedExtensions: ['.js', '.jsx', '.ts', '.tsx', '.vue', '.svelte'],
};

/**
 * Initialize auto-lint settings from localStorage
 */
function initAutoLint() {
  const saved = localStorage.getItem('autoLintEnabled');
  if (saved !== null) {
    autoLintState.enabled = saved === 'true';
  }
  
  // Update settings UI if exists
  const toggle = document.getElementById('settingAutoLint');
  if (toggle) {
    toggle.checked = autoLintState.enabled;
  }
  
  console.log('🔧 Auto-lint initialized, enabled:', autoLintState.enabled);
}

/**
 * Toggle auto-lint on/off
 */
function toggleAutoLint(enabled = null) {
  if (enabled === null) {
    autoLintState.enabled = !autoLintState.enabled;
  } else {
    autoLintState.enabled = enabled;
  }
  
  localStorage.setItem('autoLintEnabled', autoLintState.enabled.toString());
  
  showNotification(
    autoLintState.enabled ? '✓ Auto-lint enabled' : '⊘ Auto-lint disabled',
    autoLintState.enabled ? 'success' : 'info'
  );
  
  return autoLintState.enabled;
}

/**
 * Check if a file should be linted based on extension
 * @param {string} filePath - Path to the file
 */
function shouldLintFile(filePath) {
  if (!filePath) return false;
  
  const ext = '.' + filePath.split('.').pop().toLowerCase();
  return autoLintState.supportedExtensions.includes(ext);
}

/**
 * Run ESLint --fix on generated code and return results
 * @param {string} filePath - Path to the file to lint
 * @param {string} code - The code content (optional, for preview)
 * @returns {Object} - { fixed: boolean, fixCount: number, errors: [], warnings: [], fixedCode: string }
 */
async function autoLintFile(filePath, code = null) {
  if (!autoLintState.enabled) {
    return { fixed: false, skipped: true, reason: 'Auto-lint disabled' };
  }
  
  if (!shouldLintFile(filePath)) {
    return { fixed: false, skipped: true, reason: 'File type not supported' };
  }
  
  try {
    const response = await fetch('/api/lint', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ 
        filePath, 
        code,
        fix: true 
      })
    });
    
    const result = await response.json();
    
    if (result.error) {
      return { fixed: false, error: result.error };
    }
    
    // Store in history
    if (result.fixCount > 0) {
      autoLintState.fixHistory.push({
        filePath,
        fixCount: result.fixCount,
        timestamp: Date.now(),
        fixes: result.fixes || []
      });
      
      // Keep only last 50 entries
      if (autoLintState.fixHistory.length > 50) {
        autoLintState.fixHistory = autoLintState.fixHistory.slice(-50);
      }
    }
    
    autoLintState.lastResults = result;
    return result;
    
  } catch (error) {
    console.error('Auto-lint error:', error);
    return { fixed: false, error: error.message };
  }
}

/**
 * Auto-lint code and show toast notification with results
 * @param {string} filePath - Path to the file
 * @param {string} code - The code content
 * @param {boolean} showToast - Whether to show toast notification
 */
async function autoLintAndNotify(filePath, code = null, showToast = true) {
  const result = await autoLintFile(filePath, code);
  
  if (result.skipped) {
    return result;
  }
  
  if (result.error) {
    if (showToast) {
      showNotification(`⚠ Lint error: ${result.error}`, 'warning');
    }
    return result;
  }
  
  if (result.fixCount > 0 && showToast) {
    showAutoLintToast(result);
  }
  
  return result;
}

/**
 * Show a detailed toast for auto-lint results
 * @param {Object} result - Lint result object
 */
function showAutoLintToast(result) {
  const { fixCount, errors, warnings, fixes } = result;
  
  // Create detailed toast content
  let message = `🔧 Auto-fixed ${fixCount} lint issue${fixCount !== 1 ? 's' : ''}`;
  
  if (errors?.length > 0) {
    message += `\n⚠ ${errors.length} error${errors.length !== 1 ? 's' : ''} remain`;
  }
  
  // Show toast
  if (typeof showToast === 'function') {
    showToast(message, fixCount > 0 ? 'success' : 'info', {
      duration: 4000,
      action: fixes?.length > 0 ? {
        label: 'View fixes',
        onClick: () => showAutoLintDetails(result)
      } : null
    });
  } else {
    showNotification(message, fixCount > 0 ? 'success' : 'info');
  }
}

/**
 * Show detailed auto-lint fixes in a modal/panel
 * @param {Object} result - Lint result with fixes
 */
function showAutoLintDetails(result) {
  const { fixes, filePath, errors, warnings } = result;
  
  // Create modal content
  let html = `
    <div class="auto-lint-details">
      <div class="auto-lint-header">
        <span class="auto-lint-icon">🔧</span>
        <span class="auto-lint-title">Auto-Lint Results</span>
      </div>
      <div class="auto-lint-file">${escapeHtml(filePath || 'Unknown file')}</div>
  `;
  
  if (fixes?.length > 0) {
    html += `
      <div class="auto-lint-section">
        <div class="auto-lint-section-header">✓ Fixes Applied (${fixes.length})</div>
        <ul class="auto-lint-list">
    `;
    
    for (const fix of fixes.slice(0, 10)) {
      html += `
        <li class="auto-lint-item fix">
          <span class="lint-rule">${escapeHtml(fix.rule || 'unknown')}</span>
          <span class="lint-message">${escapeHtml(fix.message || '')}</span>
          ${fix.line ? `<span class="lint-line">Line ${fix.line}</span>` : ''}
        </li>
      `;
    }
    
    if (fixes.length > 10) {
      html += `<li class="auto-lint-more">... and ${fixes.length - 10} more</li>`;
    }
    
    html += '</ul></div>';
  }
  
  if (errors?.length > 0) {
    html += `
      <div class="auto-lint-section">
        <div class="auto-lint-section-header error">✗ Remaining Errors (${errors.length})</div>
        <ul class="auto-lint-list">
    `;
    
    for (const err of errors.slice(0, 5)) {
      html += `
        <li class="auto-lint-item error">
          <span class="lint-rule">${escapeHtml(err.ruleId || 'error')}</span>
          <span class="lint-message">${escapeHtml(err.message || '')}</span>
          <span class="lint-line">Line ${err.line || '?'}</span>
        </li>
      `;
    }
    
    if (errors.length > 5) {
      html += `<li class="auto-lint-more">... and ${errors.length - 5} more</li>`;
    }
    
    html += '</ul></div>';
  }
  
  if (warnings?.length > 0) {
    html += `
      <div class="auto-lint-section">
        <div class="auto-lint-section-header warning">⚠ Warnings (${warnings.length})</div>
        <ul class="auto-lint-list">
    `;
    
    for (const warn of warnings.slice(0, 3)) {
      html += `
        <li class="auto-lint-item warning">
          <span class="lint-rule">${escapeHtml(warn.ruleId || 'warning')}</span>
          <span class="lint-message">${escapeHtml(warn.message || '')}</span>
        </li>
      `;
    }
    
    html += '</ul></div>';
  }
  
  html += '</div>';
  
  // Show in modal or toast panel
  if (typeof showModal === 'function') {
    showModal('Auto-Lint Details', html);
  } else {
    // Fallback: show in console
    console.log('Auto-lint details:', result);
  }
}

/**
 * Get auto-lint history
 * @param {number} limit - Number of entries to return
 */
function getAutoLintHistory(limit = 10) {
  return autoLintState.fixHistory.slice(-limit);
}

/**
 * Clear auto-lint history
 */
function clearAutoLintHistory() {
  autoLintState.fixHistory = [];
  autoLintState.lastResults = null;
}

/**
 * Hook into agent code generation to auto-lint
 * Call this after agent generates code
 * @param {string} filePath - File that was modified
 * @param {string} newCode - The new code content
 */
async function onAgentCodeGenerated(filePath, newCode) {
  if (!autoLintState.enabled) return;
  
  agentTerminalLog('Running auto-lint...', 'info');
  
  const result = await autoLintAndNotify(filePath, null, true);
  
  if (result.fixed && result.fixCount > 0) {
    agentTerminalLog(`Auto-fixed ${result.fixCount} lint issue(s)`, 'success');
    
    // Reload the file in editor if open
    if (typeof refreshOpenFile === 'function') {
      refreshOpenFile(filePath);
    }
  } else if (result.errors?.length > 0) {
    agentTerminalLog(`${result.errors.length} lint error(s) need manual attention`, 'warning');
  }
  
  return result;
}

// Helper to escape HTML
function escapeHtml(str) {
  if (!str) return '';
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// Export functions
window.initAutoLint = initAutoLint;
window.toggleAutoLint = toggleAutoLint;
window.autoLintFile = autoLintFile;
window.autoLintAndNotify = autoLintAndNotify;
window.showAutoLintDetails = showAutoLintDetails;
window.getAutoLintHistory = getAutoLintHistory;
window.clearAutoLintHistory = clearAutoLintHistory;
window.onAgentCodeGenerated = onAgentCodeGenerated;
window.shouldLintFile = shouldLintFile;

// Initialize on load
document.addEventListener('DOMContentLoaded', initAutoLint);
